# EVOLVE-BLOCK-START
import networkx as nx
import json
import os
import pandas as pd
from typing import Dict, List
import heapq


def search_algorithm(src, dsts, G, num_partitions):
    h = G.copy()
    h.remove_edges_from(list(h.in_edges(src)) + list(nx.selfloop_edges(h)))
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Build a minimum-cost Steiner tree using greedy heuristic
    # Key insight: in broadcast, shared edges between destination paths
    # only incur cost once, so maximizing path sharing reduces total cost.

    # Parent pointers for the tree (maps node -> parent node)
    parent = {}
    tree_nodes = {src}
    remaining_dsts = set(dsts)

    # Greedy Steiner tree: repeatedly connect the cheapest unreached destination
    while remaining_dsts:
        best_cost = float('inf')
        best_dst = None
        best_path = None

        for dst in remaining_dsts:
            # Find cheapest path from ANY tree node to this destination
            for tree_node in tree_nodes:
                try:
                    path = nx.dijkstra_path(h, tree_node, dst, weight="cost")
                    cost = sum(h[path[i]][path[i+1]]['cost'] for i in range(len(path)-1))
                    if cost < best_cost:
                        best_cost = cost
                        best_dst = dst
                        best_path = path
                except (nx.NetworkXNoPath, KeyError):
                    continue

        if best_dst is None:
            # Fallback: try direct paths for remaining destinations
            for dst in list(remaining_dsts):
                try:
                    path = nx.dijkstra_path(h, src, dst, weight="cost")
                    best_path = path
                    best_dst = dst
                    break
                except (nx.NetworkXNoPath, KeyError):
                    remaining_dsts.discard(dst)
            if best_dst is None:
                break

        # Add path nodes to tree with parent pointers
        for i in range(1, len(best_path)):
            node = best_path[i]
            if node not in tree_nodes:
                parent[node] = best_path[i-1]
                tree_nodes.add(node)

        remaining_dsts.discard(best_dst)

    # For each destination, trace path from src through the tree
    for dst in dsts:
        # Trace from dst back to src using parent pointers
        path_nodes = []
        current = dst
        visited = set()
        while current is not None and current != src and current not in visited:
            visited.add(current)
            path_nodes.append(current)
            current = parent.get(current)

        if current == src:
            path_nodes.append(src)
            path_nodes.reverse()
        else:
            # Fallback to Dijkstra if tree tracing fails
            try:
                path_nodes = nx.dijkstra_path(h, src, dst, weight="cost")
            except (nx.NetworkXNoPath, KeyError):
                continue

        # Add edges to topology for all partitions
        for i in range(len(path_nodes) - 1):
            s, t = path_nodes[i], path_nodes[i+1]
            for j in range(num_partitions):
                bc_topology.append_dst_partition_path(dst, j, [s, t, G[s][t]])

    return bc_topology


class SingleDstPath(Dict):
    partition: int
    edges: List[List]  # [[src, dst, edge data]]


class BroadCastTopology:
    def __init__(self, src: str, dsts: List[str], num_partitions: int = 4, paths: Dict[str, SingleDstPath] = None):
        self.src = src  # single str
        self.dsts = dsts  # list of strs
        self.num_partitions = num_partitions

        # dict(dst) --> dict(partition) --> list(nx.edges)
        # example: {dst1: {partition1: [src->node1, node1->dst1], partition 2: [src->dst1]}}
        if paths is not None:
            self.paths = paths
            self.set_graph()
        else:
            self.paths = {dst: {str(i): None for i in range(num_partitions)} for dst in dsts}

    def get_paths(self):
        print(f"now the set path is: {self.paths}")
        return self.paths

    def set_num_partitions(self, num_partitions: int):
        self.num_partitions = num_partitions

    def set_dst_partition_paths(self, dst: str, partition: int, paths: List[List]):
        """
        Set paths for partition = partition to reach dst
        """
        partition = str(partition)
        self.paths[dst][partition] = paths

    def append_dst_partition_path(self, dst: str, partition: int, path: List):
        """
        Append path for partition = partition to reach dst
        """
        partition = str(partition)
        if self.paths[dst][partition] is None:
            self.paths[dst][partition] = []
        self.paths[dst][partition].append(path)

def make_nx_graph(cost_path=None, throughput_path=None, num_vms=1):
    """
    Default graph with capacity constraints and cost info
    nodes: regions, edges: links
