            paths_cache[node] = {}

    # Strategy 1: Independent shortest paths from src (baseline star topology)
    # Compute union of all shortest paths - shared edges counted once
    star_edges = set()
    star_paths = {}
    for dst in dsts:
        if dst in paths_cache.get(src, {}):
            path = paths_cache[src][dst]
            star_paths[dst] = path
            for i in range(len(path) - 1):
                star_edges.add((path[i], path[i+1]))
    star_cost = sum(h[u][v]['cost'] for u, v in star_edges if h.has_edge(u, v))

    # Strategy 2: Greedy Steiner tree - try all permutations for small dst count
    # For each permutation, greedily connect destinations and track total tree edge cost
    best_tree_cost = float('inf')
    best_tree_parent = None

    dst_list = list(dsts)
    n_dsts = len(dst_list)

    if n_dsts <= 8:
        perms = list(permutations(range(n_dsts)))
    else:
        # For large destination counts, sample random permutations
        import random
        perms = [tuple(random.sample(range(n_dsts), n_dsts)) for _ in range(5000)]
        perms.append(tuple(range(n_dsts)))

    for perm in perms:
        tree_nodes = {src}
        tree_edges = set()
        parent = {src: None}
        valid = True

        for idx in perm:
            dst = dst_list[idx]
            # Find cheapest path from any tree node to this destination
            best_path_cost = float('inf')
            best_path = None
            for tnode in tree_nodes:
                if dst in dist.get(tnode, {}):
                    c = dist[tnode][dst]
                    if c < best_path_cost:
                        best_path_cost = c
                        best_path = paths_cache[tnode][dst]

            if best_path is None:
                valid = False
                break

            # Add new edges from this path to tree
            for i in range(1, len(best_path)):
                node = best_path[i]
                if node not in tree_nodes:
                    parent[node] = best_path[i-1]
                    tree_nodes.add(node)
                    tree_edges.add((best_path[i-1], node))
                elif i > 0 and best_path[i-1] in tree_nodes:
                    # Edge between two tree nodes that might be new
                    # Only add if predecessor is correct in the path
                    pass

        if not valid:
            continue

        # Compute total cost of tree edges
        total_cost = sum(h[u][v]['cost'] for u, v in tree_edges if h.has_edge(u, v))

        if total_cost < best_tree_cost:
            best_tree_cost = total_cost
            best_tree_parent = dict(parent)

    # Strategy 3: Hub-based approach
    # Try routing all destinations through a single hub node
    best_hub_cost = float('inf')
    best_hub = None
    best_hub_edges = None
    for hub in all_nodes:
        if hub == src:
            continue
        if hub not in dist.get(src, {}):
            continue
        src_to_hub_cost = dist[src][hub]
        hub_edges = set()
        hub_path = paths_cache[src][hub]
        for i in range(len(hub_path) - 1):
            hub_edges.add((hub_path[i], hub_path[i+1]))

        all_reachable = True
        for dst in dsts:
            if dst == hub:
                continue
            if dst in dist.get(hub, {}):
                path = paths_cache[hub][dst]
                for i in range(len(path) - 1):
                    hub_edges.add((path[i], path[i+1]))
            elif dst in dist.get(src, {}):
                # Fallback: direct from src
                path = paths_cache[src][dst]
                for i in range(len(path) - 1):
                    hub_edges.add((path[i], path[i+1]))
            else:
                all_reachable = False
                break

        if not all_reachable:
            continue

        hub_total = sum(h[u][v]['cost'] for u, v in hub_edges if h.has_edge(u, v))
        if hub_total < best_hub_cost:
            best_hub_cost = hub_total
            best_hub = hub
            best_hub_edges = hub_edges

    # Pick the best strategy
    choices = []
    if star_paths and len(star_paths) == len(dsts):
