# EVOLVE-BLOCK-START
import networkx as nx
import json
import os
import pandas as pd
from typing import Dict, List
from itertools import permutations, combinations


def search_algorithm(src, dsts, G, num_partitions):
    h = G.copy()
    h.remove_edges_from(list(h.in_edges(src)) + list(nx.selfloop_edges(h)))
    # Remove edges with None cost (unusable)
    remove_edges = [(u, v) for u, v, d in h.edges(data=True) if d.get('cost') is None]
    h.remove_edges_from(remove_edges)
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute all-pairs shortest paths
    all_nodes = list(h.nodes())
    dist = {}
    paths_cache = {}
    for node in all_nodes:
        try:
            lengths, node_paths = nx.single_source_dijkstra(h, node, weight="cost")
            dist[node] = lengths
            paths_cache[node] = node_paths
        except Exception:
            dist[node] = {}
            paths_cache[node] = {}

    terminals = [src] + list(dsts)

    # Helper: compute total unique edge cost for a set of paths
    def tree_cost_from_paths(path_dict):
        edges = set()
        for dst, path in path_dict.items():
            for i in range(len(path) - 1):
                edges.add((path[i], path[i+1]))
        return sum(h[u][v]['cost'] for u, v in edges if h.has_edge(u, v))

    # Strategy 1: Independent shortest paths (star topology)
    star_paths = {}
    for dst in dsts:
        if dst in paths_cache.get(src, {}):
            star_paths[dst] = paths_cache[src][dst]
    star_cost = tree_cost_from_paths(star_paths) if len(star_paths) == len(dsts) else float('inf')

    # Strategy 2: Minimum Spanning Arborescence on metric closure
    # Build complete directed graph on terminals with shortest path costs
    arb_cost = float('inf')
    arb_paths = {}
    try:
        metric_graph = nx.DiGraph()
        for u in terminals:
            for v in terminals:
                if u != v and v in dist.get(u, {}):
                    metric_graph.add_edge(u, v, weight=dist[u][v])
        # Find minimum spanning arborescence rooted at src
        arb = nx.minimum_spanning_arborescence(metric_graph, attr='weight')
        # Map arborescence edges back to original paths
        # Build path from src to each destination through the arborescence
        arb_tree_paths = {}
        for dst in dsts:
            # BFS/DFS in arborescence to find path from src to dst
            try:
                arb_path_terminals = nx.shortest_path(arb, src, dst)
                # Map each arborescence edge back to original shortest path
                full_path = [arb_path_terminals[0]]
                for i in range(len(arb_path_terminals) - 1):
                    u, v = arb_path_terminals[i], arb_path_terminals[i+1]
                    orig_path = paths_cache[u][v]
                    full_path.extend(orig_path[1:])
                arb_tree_paths[dst] = full_path
            except (nx.NetworkXNoPath, KeyError):
                break
        if len(arb_tree_paths) == len(dsts):
            arb_cost = tree_cost_from_paths(arb_tree_paths)
            arb_paths = arb_tree_paths
    except Exception:
        pass

    # Strategy 3: Single-hub approach (try each node as hub)
    best_hub_cost = float('inf')
    best_hub_paths = {}
    for hub in all_nodes:
        if hub == src:
            continue
        if hub not in dist.get(src, {}):
            continue
        hub_path_dict = {}
        all_reachable = True
        for dst in dsts:
            if dst == hub:
                hub_path_dict[dst] = paths_cache[src][hub]
            elif dst in dist.get(hub, {}):
                # Route through hub
                src_hub_path = paths_cache[src][hub]
                hub_dst_path = paths_cache[hub][dst]
                hub_path_dict[dst] = src_hub_path + hub_dst_path[1:]
            elif dst in dist.get(src, {}):
                # Direct if hub can't reach
                hub_path_dict[dst] = paths_cache[src][dst]
            else:
                all_reachable = False
                break
        if not all_reachable or len(hub_path_dict) != len(dsts):
            continue
        cost = tree_cost_from_paths(hub_path_dict)
        if cost < best_hub_cost:
            best_hub_cost = cost
            best_hub_paths = dict(hub_path_dict)

    # Strategy 4: Two-hub approach (route subsets through different hubs)
    best_two_hub_cost = float('inf')
    best_two_hub_paths = {}
    # Only try promising hub candidates (top 10 cheapest to reach from src)
    hub_candidates = sorted(
        [n for n in all_nodes if n != src and n not in dsts and n in dist.get(src, {})],
        key=lambda n: dist[src].get(n, float('inf'))
    )[:15]

    for hub1, hub2 in combinations(hub_candidates, 2):
        if hub2 not in dist.get(src, {}):
            continue
        # For each destination, pick the cheaper option: via hub1, via hub2, or direct
        two_hub_path_dict = {}
        all_ok = True
        for dst in dsts:
            options = []
            # Direct
            if dst in dist.get(src, {}):
                options.append(('direct', dist[src][dst], paths_cache[src][dst]))
            # Via hub1
            if dst in dist.get(hub1, {}):
                path = paths_cache[src][hub1] + paths_cache[hub1][dst][1:]
                options.append(('hub1', None, path))
            # Via hub2
            if dst in dist.get(hub2, {}):
                path = paths_cache[src][hub2] + paths_cache[hub2][dst][1:]
                options.append(('hub2', None, path))
            if not options:
                all_ok = False
                break
            # We can't easily compare since tree cost depends on sharing
            # Use heuristic: prefer shorter total path cost
            best_option = min(options, key=lambda x: sum(
                h[x[2][i]][x[2][i+1]]['cost']
                for i in range(len(x[2])-1)
                if h.has_edge(x[2][i], x[2][i+1])
            ))
            two_hub_path_dict[dst] = best_option[2]

        if not all_ok or len(two_hub_path_dict) != len(dsts):
            continue
        cost = tree_cost_from_paths(two_hub_path_dict)
        if cost < best_two_hub_cost:
            best_two_hub_cost = cost
            best_two_hub_paths = dict(two_hub_path_dict)

    # Strategy 5: Greedy Steiner tree with improved "new edge cost" metric
    best_greedy_cost = float('inf')
    best_greedy_paths = {}

    # Try multiple orderings: sort by distance, reverse, random
    orderings = []
    # Sort by distance from src (nearest first)
    sorted_by_dist = sorted(dsts, key=lambda d: dist.get(src, {}).get(d, float('inf')))
    orderings.append(sorted_by_dist)
    # Farthest first
    orderings.append(list(reversed(sorted_by_dist)))
    # If small enough, try all permutations
    if len(dsts) <= 7:
        for perm in permutations(dsts):
            orderings.append(list(perm))

    for ordering in orderings:
        tree_nodes = {src}
        parent = {src: None}
        valid = True

        for dst in ordering:
            # Find path from nearest tree node using NEW edge cost metric
            best_new_cost = float('inf')
            best_path = None
            for tnode in tree_nodes:
                if dst not in dist.get(tnode, {}):
                    continue
                path = paths_cache[tnode][dst]
                # Compute cost of only NEW edges (target not in tree)
                new_cost = 0
                for i in range(len(path) - 1):
                    if path[i+1] not in tree_nodes:
                        new_cost += h[path[i]][path[i+1]]['cost']
                if new_cost < best_new_cost:
                    best_new_cost = new_cost
                    best_path = path

            if best_path is None:
                valid = False
                break

            for i in range(1, len(best_path)):
                node = best_path[i]
                if node not in tree_nodes:
                    parent[node] = best_path[i-1]
                    tree_nodes.add(node)

        if not valid:
            continue

        # Reconstruct paths for each destination
        greedy_path_dict = {}
        for dst in dsts:
            path_nodes = []
            current = dst
            visited = set()
            while current is not None and current != src and current not in visited:
                visited.add(current)
                path_nodes.append(current)
                current = parent.get(current)
            if current == src:
