def search_algorithm(src, dsts, G, num_partitions):
    h = G.copy()
    h.remove_edges_from(list(h.in_edges(src)) + list(nx.selfloop_edges(h)))
    remove_edges = [(u, v) for u, v, d in h.edges(data=True) if d.get('cost') is None]
    h.remove_edges_from(remove_edges)
    bc_topology = BroadCastTopology(src, dsts, num_partitions)

    # Precompute all-pairs shortest paths
    all_nodes = list(h.nodes())
    dist = {}
    paths_cache = {}
    for node in all_nodes:
        try:
            lengths, node_paths = nx.single_source_dijkstra(h, node, weight="cost")
            dist[node] = lengths
            paths_cache[node] = node_paths
        except Exception:
            dist[node] = {}
            paths_cache[node] = {}

    def tree_cost_from_paths(path_dict):
        edges = set()
        for dst, path in path_dict.items():
            for i in range(len(path) - 1):
                edges.add((path[i], path[i+1]))
        return sum(h[u][v]['cost'] for u, v in edges if h.has_edge(u, v))

    # Strategy 1: Independent shortest paths (star)
    star_paths = {}
    for dst in dsts:
        if dst in paths_cache.get(src, {}):
            star_paths[dst] = paths_cache[src][dst]
    star_cost = tree_cost_from_paths(star_paths) if len(star_paths) == len(dsts) else float('inf')

    # Strategy 2: Minimum Spanning Arborescence on metric closure
    arb_cost = float('inf')
    arb_paths = {}
    try:
        terminals = [src] + list(dsts)
        metric_graph = nx.DiGraph()
        for u in terminals:
            for v in terminals:
                if u != v and v in dist.get(u, {}):
                    metric_graph.add_edge(u, v, weight=dist[u][v])
        arb = nx.minimum_spanning_arborescence(metric_graph, attr='weight')
        arb_tree_paths = {}
        for dst in dsts:
            try:
                arb_path_terminals = nx.shortest_path(arb, src, dst)
                full_path = [arb_path_terminals[0]]
                for i in range(len(arb_path_terminals) - 1):
                    u, v = arb_path_terminals[i], arb_path_terminals[i+1]
                    orig_path = paths_cache[u][v]
                    full_path.extend(orig_path[1:])
                arb_tree_paths[dst] = full_path
            except (nx.NetworkXNoPath, KeyError):
                break
        if len(arb_tree_paths) == len(dsts):
            arb_cost = tree_cost_from_paths(arb_tree_paths)
            arb_paths = arb_tree_paths
    except Exception:
        pass

    # Strategy 3: Single-hub approach
    best_hub_cost = float('inf')
    best_hub_paths = {}
    for hub in all_nodes:
        if hub == src:
            continue
        if hub not in dist.get(src, {}):
