                hub_path_dict[dst] = paths_cache[src][hub]
            elif dst in dist.get(hub, {}):
                hub_path_dict[dst] = paths_cache[src][hub] + paths_cache[hub][dst][1:]
            elif dst in dist.get(src, {}):
                hub_path_dict[dst] = paths_cache[src][dst]
            else:
