            if dst in dist.get(hub1, {}):
                options.append(paths_cache[src][hub1] + paths_cache[hub1][dst][1:])
            if dst in dist.get(hub2, {}):
                options.append(paths_cache[src][hub2] + paths_cache[hub2][dst][1:])
