                h[p[i]][p[i+1]]['cost'] for i in range(len(p)-1) if h.has_edge(p[i], p[i+1])
            ))
            two_hub_path_dict[dst] = best_option
        if not all_ok or len(two_hub_path_dict) != len(dsts):
