        if cost < best_two_hub_cost:
            best_two_hub_cost = cost
            best_two_hub_paths = dict(two_hub_path_dict)

    # Strategy 5: Greedy Steiner tree with permutations
    best_greedy_cost = float('inf')
    best_greedy_paths = {}
