    # Pick best strategy
    strategies = [
        (star_cost, star_paths),
        (arb_cost, arb_paths),
        (best_hub_cost, best_hub_paths),
        (best_two_hub_cost, best_two_hub_paths),
        (best_greedy_cost, best_greedy_paths),
    ]
    best_cost = float('inf')
    best_paths = None
